import React, { useState, useEffect } from 'react';
import { useLanguage } from '../lib/LanguageContext';
import { useAuth } from '../lib/AuthContext';
import { Siren, AlertTriangle, CheckCircle, Clock, Plus, Lock, XCircle, Loader } from 'lucide-react';
import { Link } from 'react-router-dom';
import { supabase } from '../lib/supabase';

export const SOS: React.FC = () => {
  const { t } = useLanguage();
  const { user } = useAuth();
  const [showForm, setShowForm] = useState(false);

  const [history, setHistory] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);

  const [formData, setFormData] = useState({
    issueType: 'hardware',
    description: '',
    urgency: 'high'
  });

  // Check Subscription
  const hasAccess = user?.subscriptions?.sos_business;

  const fetchTickets = async () => {
    if (!user) return;
    setLoading(true);
    // Fetch tickets where user_id matches current user
    const { data, error } = await supabase
        .from('sos_tickets')
        .select('*')
        .eq('user_id', user.id)
        .order('created_at', { ascending: false });

    if (data) setHistory(data);
    if (error) console.error('Error fetching tickets', error);
    setLoading(false);
  };

  useEffect(() => {
    if (hasAccess) {
        fetchTickets();
    }
  }, [hasAccess, user]);

  if (!hasAccess) {
      return (
        <div className="container mx-auto px-4 md:px-6 py-20 flex items-center justify-center min-h-[60vh]">
            <div className="bg-bunker-900 border border-neon-red/30 p-10 max-w-lg text-center clip-corner relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-1 bg-neon-red animate-pulse"></div>
                <div className="w-20 h-20 bg-bunker-950 border border-neon-red/50 rounded-full flex items-center justify-center mx-auto mb-6 text-neon-red">
                    <Lock size={40} />
                </div>
                <h1 className="text-3xl font-tech font-bold text-white mb-4 tracking-widest uppercase">{t.sos.restrictedTitle}</h1>
                <p className="text-slate-400 mb-8 leading-relaxed">
                    {t.sos.restrictedDesc}
                </p>
                <div className="font-mono text-xs text-neon-red/70 border border-neon-red/20 py-2 px-4 inline-block">
                    ERROR_CODE: SUB_MISSING_SOS_BIZ
                </div>
                <div className="mt-8">
                    <Link to="/contact" className="text-white underline hover:text-neon-green transition-colors font-mono text-sm">Contact Support</Link>
                </div>
            </div>
        </div>
      );
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;
    setSubmitting(true);

    try {
        const { error } = await supabase.from('sos_tickets').insert([{
            user_id: user.id,
            user_email: user.email,
            issue_type: formData.issueType,
            description: formData.description,
            urgency: formData.urgency,
            status: 'pending'
        }]);

        if (error) throw error;

        // Reset and refresh
        setFormData({ issueType: 'hardware', description: '', urgency: 'high' });
        setShowForm(false);
        fetchTickets();

    } catch (error) {
        console.error("Error creating ticket:", error);
        alert("Failed to create ticket.");
    } finally {
        setSubmitting(false);
    }
  };

  const getStatusBadge = (status: string) => {
      switch(status) {
          case 'resolved': return <span className="inline-flex items-center gap-1 text-neon-green bg-neon-green/10 px-2 py-0.5 text-[10px] font-mono uppercase border border-neon-green/20"><CheckCircle size={10} /> Resolved</span>;
          case 'pending': return <span className="inline-flex items-center gap-1 text-yellow-500 bg-yellow-500/10 px-2 py-0.5 text-[10px] font-mono uppercase border border-yellow-500/20"><Clock size={10} /> Pending</span>;
          case 'in_progress': return <span className="inline-flex items-center gap-1 text-neon-cyan bg-neon-cyan/10 px-2 py-0.5 text-[10px] font-mono uppercase border border-neon-cyan/20"><Loader size={10} className="animate-spin"/> Processing</span>;
          case 'cancelled': return <span className="inline-flex items-center gap-1 text-red-500 bg-red-500/10 px-2 py-0.5 text-[10px] font-mono uppercase border border-red-500/20"><XCircle size={10} /> Cancelled</span>;
          default: return <span className="text-slate-400 text-xs">{status}</span>;
      }
  };

  return (
    <div className="container mx-auto px-4 md:px-6 py-12">
      <div className="bg-bunker-900 border border-white/10 p-8 md:p-12 mb-12 relative overflow-hidden clip-corner">
         <div className="absolute inset-0 bg-grid-pattern opacity-10"></div>
         <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-8">
            <div>
                <h1 className="text-3xl md:text-5xl font-tech font-bold text-white mb-2 flex items-center gap-3">
                    <Siren className="text-neon-red animate-pulse" />
                    {t.sos.title}
                </h1>
                <p className="text-slate-400 max-w-lg">{t.sos.subtitle}</p>
            </div>
            {!showForm && (
                <button 
                    onClick={() => setShowForm(true)}
                    className="group relative px-8 py-6 bg-neon-red text-bunker-950 font-bold font-tech text-xl tracking-widest clip-corner hover:bg-white transition-all shadow-[0_0_20px_rgba(255,0,60,0.4)]"
                >
                    <span className="relative z-10 flex items-center gap-3">
                        <AlertTriangle className="animate-pulse" />
                        {t.sos.createBtn}
                    </span>
                </button>
            )}
         </div>
      </div>

      {showForm && (
        <div className="bg-bunker-950 border border-neon-red/30 p-6 md:p-8 mb-12 animate-fade-in-up">
            <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
                <Plus className="text-neon-red" />
                {t.sos.form.title}
            </h2>
            <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                    <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">{t.sos.form.issueType}</label>
                    <select 
                        className="w-full bg-bunker-900 border border-white/10 px-4 py-3 text-white focus:border-neon-red outline-none"
                        value={formData.issueType}
                        onChange={e => setFormData({...formData, issueType: e.target.value})}
                    >
                        <option value="hardware">Hardware Failure</option>
                        <option value="software">Software Bug</option>
                        <option value="network">Network/Connectivity</option>
                        <option value="security">Security Breach</option>
                        <option value="other">Other</option>
                    </select>
                </div>
                <div>
                    <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">{t.sos.form.urgency}</label>
                    <select 
                        className="w-full bg-bunker-900 border border-white/10 px-4 py-3 text-white focus:border-neon-red outline-none"
                        value={formData.urgency}
                        onChange={e => setFormData({...formData, urgency: e.target.value})}
                    >
                        <option value="low">Low (Next Business Day)</option>
                        <option value="medium">Medium (4 Hours)</option>
                        <option value="high">High (Immediate)</option>
                        <option value="critical">CRITICAL (System Down)</option>
                    </select>
                </div>
                <div className="md:col-span-2">
                    <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">{t.sos.form.desc}</label>
                    <textarea 
                        rows={4}
                        className="w-full bg-bunker-900 border border-white/10 px-4 py-3 text-white focus:border-neon-red outline-none"
                        value={formData.description}
                        onChange={e => setFormData({...formData, description: e.target.value})}
                        required
                    ></textarea>
                </div>
                <div className="md:col-span-2 flex justify-end gap-4">
                     <button 
                        type="button" 
                        onClick={() => setShowForm(false)}
                        className="px-6 py-3 border border-white/10 text-slate-400 hover:text-white font-mono uppercase text-xs"
                    >
                        Cancel
                    </button>
                    <button 
                        type="submit" 
                        disabled={submitting}
                        className="px-8 py-3 bg-neon-red text-bunker-950 font-bold font-mono uppercase text-xs hover:bg-white transition-colors disabled:opacity-50"
                    >
                        {submitting ? 'Sending...' : t.sos.form.submit}
                    </button>
                </div>
            </form>
        </div>
      )}

      <div>
        <h2 className="text-xl font-mono text-neon-green mb-6 uppercase tracking-widest flex items-center justify-between">
            {t.sos.historyTitle}
            {loading && <Loader className="animate-spin text-slate-500" size={16} />}
        </h2>
        <div className="bg-bunker-900 border border-white/5 overflow-x-auto">
            <table className="w-full text-left border-collapse">
                <thead>
                    <tr className="bg-bunker-950 text-slate-500 font-mono text-xs uppercase border-b border-white/10">
                        <th className="p-4">{t.sos.table.id}</th>
                        <th className="p-4">{t.sos.table.date}</th>
                        <th className="p-4">{t.sos.table.issue}</th>
                        <th className="p-4">{t.sos.table.status}</th>
                        <th className="p-4 text-right">{t.sos.table.cost}</th>
                    </tr>
                </thead>
                <tbody className="text-sm font-mono text-slate-300">
                    {history.map((item) => (
                        <tr key={item.id} className="border-b border-white/5 hover:bg-white/5 transition-colors">
                            <td className="p-4 text-neon-green">SOS-{item.id}</td>
                            <td className="p-4">{new Date(item.created_at).toLocaleDateString()}</td>
                            <td className="p-4 capitalize">
                                <div>{item.issue_type}</div>
                                {item.solution && (
                                    <div className="text-[10px] text-slate-500 mt-1 max-w-xs">{item.solution}</div>
                                )}
                            </td>
                            <td className="p-4">{getStatusBadge(item.status)}</td>
                            <td className="p-4 text-right">
                                {item.cost}
                                {item.is_paid && <span className="ml-2 text-neon-green text-[10px] border border-neon-green/30 px-1 rounded">PAID</span>}
                            </td>
                        </tr>
                    ))}
                    {!loading && history.length === 0 && (
                        <tr>
                            <td colSpan={5} className="p-8 text-center text-slate-500">NO_RECORDS_FOUND</td>
                        </tr>
                    )}
                </tbody>
            </table>
        </div>
      </div>

    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useLanguage } from '../lib/LanguageContext';
import { supabase } from '../lib/supabase';
import { Users, Database, ShieldAlert, Terminal, Trash2, Edit, Loader, Plus, X, Save, Lock, Mail, Building, ToggleLeft, ToggleRight, AlertTriangle, Siren, DollarSign, Calendar, CheckSquare } from 'lucide-react';

interface AdminFormData {
  email: string;
  password: string;
  role: string;
  business_name: string;
  subscriptions: {
    [key: string]: any;
  };
}

interface SosTicketData {
    id: number | null;
    status: string;
    issue_type: string;
    urgency: string;
    description: string;
    solution: string;
    cost: string;
    is_paid: boolean;
    created_at: string;
}

export const Admin: React.FC = () => {
  const { t } = useLanguage();

  // Data States
  const [users, setUsers] = useState<any[]>([]);
  const [tickets, setTickets] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  // UI States
  const [activeTab, setActiveTab] = useState<'users' | 'sos'>('users');

  // Modal States
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isSosModalOpen, setIsSosModalOpen] = useState(false);

  // Message Modal
  const [messageModal, setMessageModal] = useState({ 
    isOpen: false, 
    title: '', 
    text: '', 
    isError: false 
  });

  // Editing States
  const [editingUserId, setEditingUserId] = useState<number | null>(null);
  const [editingTicketId, setEditingTicketId] = useState<number | null>(null);

  // Forms
  const [userFormData, setUserFormData] = useState<AdminFormData>({
    email: '',
    password: '',
    role: 'CLIENT',
    business_name: '',
    subscriptions: { sos_business: false }
  });

  const [sosFormData, setSosFormData] = useState<SosTicketData>({
      id: null,
      status: 'pending',
      issue_type: '',
      urgency: '',
      description: '',
      solution: '',
      cost: '-',
      is_paid: false,
      created_at: ''
  });

  const fetchUsers = async () => {
    const { data, error } = await supabase.from('app_users').select('*').order('id', { ascending: true });
    if (error) console.error("Error fetching users:", error);
    if (data) setUsers(data);
  };

  const fetchTickets = async () => {
    const { data, error } = await supabase
        .from('sos_tickets')
        .select('*')
        .order('created_at', { ascending: false });
    if (error) console.error("Error fetching tickets:", error);
    if (data) setTickets(data);
  };

  const fetchData = async () => {
    setLoading(true);
    await Promise.all([fetchUsers(), fetchTickets()]);
    setLoading(false);
  };

  useEffect(() => {
    fetchData();
  }, []);

  // --- Message Helper ---
  const showMessage = (title: string, text: string, isError = true) => {
    setMessageModal({ isOpen: true, title, text, isError });
  };
  const closeMessage = () => setMessageModal(prev => ({ ...prev, isOpen: false }));


  // --- USER Logic ---
  const handleOpenUserModal = (user?: any) => {
    if (user) {
        setEditingUserId(user.id);
        let userSubs = user.subscriptions;
        if (typeof userSubs === 'string') {
            try { userSubs = JSON.parse(userSubs); } catch(e) { console.error("Error parsing subs", e); }
        }
        if (!userSubs) userSubs = { sos_business: false };

        setUserFormData({
            email: user.email,
            password: user.password,
            role: user.role,
            business_name: user.business_name || '',
            subscriptions: userSubs
        });
    } else {
        setEditingUserId(null);
        setUserFormData({
            email: '',
            password: '',
            role: 'CLIENT',
            business_name: '',
            subscriptions: { sos_business: false }
        });
    }
    setIsUserModalOpen(true);
  };

  const handleDeleteUser = async (id: number) => {
    if (window.confirm(t.admin.actions.confirmDelete)) {
        const { error } = await supabase.from('app_users').delete().eq('id', id);
        if (error) showMessage("DELETE ERROR", error.message, true);
        else fetchUsers();
    }
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    const basePayload = {
        email: userFormData.email,
        password: userFormData.password,
        role: userFormData.role,
        business_name: userFormData.business_name,
    };
    const fullPayload = { ...basePayload, subscriptions: userFormData.subscriptions };

    try {
        let result;
        if (editingUserId) {
            result = await supabase.from('app_users').update(fullPayload).eq('id', editingUserId).select();
        } else {
            result = await supabase.from('app_users').insert([fullPayload]).select();
        }

        if (result.error) throw result.error;
        setIsUserModalOpen(false);
        fetchUsers();
    } catch (error: any) {
        // Fallback for missing JSONB column
        if (error.message?.includes('subscriptions')) {
            try {
                if (editingUserId) await supabase.from('app_users').update(basePayload).eq('id', editingUserId);
                else await supabase.from('app_users').insert([basePayload]);
                setIsUserModalOpen(false);
                fetchUsers();
                showMessage("PARTIAL SAVE", "User saved without subscriptions (DB column missing).", true);
                return;
            } catch(e) {}
        }
        showMessage("SAVE ERROR", error.message || 'Unknown error', true);
    }
  };

  const toggleSubscription = (key: string) => {
      setUserFormData(prev => ({
          ...prev,
          subscriptions: { ...prev.subscriptions, [key]: !prev.subscriptions[key] }
      }));
  };

  // --- SOS Logic ---
  const handleOpenSosModal = (ticket: any) => {
      setEditingTicketId(ticket.id);
      setSosFormData({
          id: ticket.id,
          status: ticket.status || 'pending',
          issue_type: ticket.issue_type,
          urgency: ticket.urgency,
          description: ticket.description,
          solution: ticket.solution || '',
          cost: ticket.cost || '-',
          is_paid: ticket.is_paid || false,
          created_at: ticket.created_at
      });
      setIsSosModalOpen(true);
  };

  const handleDeleteTicket = async (id: number) => {
      if(window.confirm(t.admin.actions.confirmDelete)) {
          const { error } = await supabase.from('sos_tickets').delete().eq('id', id);
          if (error) showMessage("DELETE ERROR", error.message, true);
          else fetchTickets();
      }
  };

  const handleSaveTicket = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!editingTicketId) return;

      const { error } = await supabase
        .from('sos_tickets')
        .update({
            status: sosFormData.status,
            cost: sosFormData.cost,
            solution: sosFormData.solution,
            is_paid: sosFormData.is_paid,
            issue_type: sosFormData.issue_type, // Allowing full edit as requested
            urgency: sosFormData.urgency,
            description: sosFormData.description,
            created_at: sosFormData.created_at // Allow date edit
        })
        .eq('id', editingTicketId);

      if (error) {
          showMessage("SAVE ERROR", error.message, true);
      } else {
          setIsSosModalOpen(false);
          fetchTickets();
      }
  };


  return (
    <div className="container mx-auto px-4 md:px-6 py-12 relative min-h-screen">
      <div className="flex items-center gap-4 mb-10 border-b border-neon-red/30 pb-6">
        <div className="p-3 bg-neon-red/10 border border-neon-red/30 rounded">
             <ShieldAlert className="text-neon-red" size={32} />
        </div>
        <div>
            <h1 className="text-3xl font-tech font-bold text-white uppercase tracking-wider">{t.admin.title}</h1>
            <p className="text-neon-red font-mono text-xs">RESTRICTED AREA // LEVEL 5 CLEARANCE</p>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex gap-1 mb-8">
          <button 
            onClick={() => setActiveTab('users')}
            className={`px-6 py-3 font-mono uppercase font-bold text-sm transition-all clip-corner-br ${
                activeTab === 'users' 
                ? 'bg-neon-green text-bunker-950' 
                : 'bg-bunker-900 text-slate-500 border border-white/10 hover:text-white'
            }`}
          >
              {t.admin.tabs.users}
          </button>
