import React, { useState, useEffect } from 'react';
import { useLanguage } from '../lib/LanguageContext';
import { useAuth } from '../lib/AuthContext';
import { Siren, AlertTriangle, CheckCircle, Clock, Plus, Lock, XCircle, Loader } from 'lucide-react';
import { Link } from 'react-router-dom';
import { supabase } from '../lib/supabase';

export const SOS: React.FC = () => {
  const { t } = useLanguage();
  const { user } = useAuth();
  const [showForm, setShowForm] = useState(false);

  const [history, setHistory] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);

  const [formData, setFormData] = useState({
    issueType: 'hardware',
    description: '',
    urgency: 'high'
  });

  // Check Subscription
  const hasAccess = user?.subscriptions?.sos_business;

  const fetchTickets = async () => {
    if (!user) return;
    setLoading(true);
    // Fetch tickets where user_id matches current user
    const { data, error } = await supabase
        .from('sos_tickets')
        .select('*')
        .eq('user_id', user.id)
        .order('created_at', { ascending: false });

    if (data) setHistory(data);
    if (error) console.error('Error fetching tickets', error);
    setLoading(false);
  };

  useEffect(() => {
    if (hasAccess) {
        fetchTickets();
    }
  }, [hasAccess, user]);

  if (!hasAccess) {
      return (
        <div className="container mx-auto px-4 md:px-6 py-20 flex items-center justify-center min-h-[60vh]">
