import React, { useEffect, useState } from 'react';
import { useLanguage } from '../lib/LanguageContext';
import { useAuth } from '../lib/AuthContext';
import { supabase } from '../lib/supabase';
import { Activity, CreditCard, ShieldCheck, Clock, Zap, CheckCircle, AlertTriangle, Loader, XCircle } from 'lucide-react';
import { Link } from 'react-router-dom';

export const Dashboard: React.FC = () => {
  const { t } = useLanguage();
  const { user } = useAuth();

  const [loading, setLoading] = useState(true);
  const [activeCount, setActiveCount] = useState(0);
  const [totalSaved, setTotalSaved] = useState(0);
  const [latestTicket, setLatestTicket] = useState<any>(null);

  // Helper to parse cost strings
  const parseCost = (costStr: string | null): number => {
      if (!costStr || costStr === '-') return 0;
      const cleaned = costStr.replace(/[^0-9.-]+/g, "");
      return parseFloat(cleaned) || 0;
  };

  useEffect(() => {
    const fetchDashboardData = async () => {
        if (!user) return;
        setLoading(true);

        // Fetch user's tickets
        const { data, error } = await supabase
            .from('sos_tickets')
            .select('*')
            .eq('user_id', user.id)
            .order('created_at', { ascending: false });

        if (error) {
            console.error("Error fetching dashboard data:", error);
        } else if (data) {
            // 1. Active Tickets Count (Pending or In Progress)
            const active = data.filter(t => t.status === 'pending' || t.status === 'in_progress').length;
            setActiveCount(active);

            // 2. Calculate Savings (Market - Our Cost)
            let savings = 0;
            data.forEach(t => {
                const ourCost = parseCost(t.cost);
                const marketCost = parseCost(t.market_cost);
                if (ourCost > 0 && marketCost > 0) {
                    savings += (marketCost - ourCost);
                }
            });
            setTotalSaved(savings);

            // 3. Latest Activity
            if (data.length > 0) {
                setLatestTicket(data[0]);
            }
        }
        setLoading(false);
    };

    fetchDashboardData();
  }, [user]);

  const getStatusIcon = (status: string) => {
      switch(status) {
          case 'resolved': return <CheckCircle size={20} className="text-neon-green" />;
          case 'pending': return <Clock size={20} className="text-yellow-500" />;
          case 'in_progress': return <Loader size={20} className="text-neon-cyan animate-spin" />;
          case 'cancelled': return <XCircle size={20} className="text-red-500" />;
          default: return <Activity size={20} className="text-slate-400" />;
      }
  };

  return (
    <div className="container mx-auto px-4 md:px-6 py-12">
      {/* Header */}
      <div className="mb-10 flex flex-col md:flex-row justify-between items-start md:items-end border-b border-white/10 pb-6">
        <div>
            <div className="text-[10px] font-mono text-neon-green mb-2 animate-pulse">SYSTEM_ONLINE</div>
            <h1 className="text-3xl md:text-5xl font-tech font-bold text-white">{t.dashboard.welcome}</h1>
        </div>
        <div className="mt-4 md:mt-0">
             <Link to="/sos" className="flex items-center gap-2 bg-neon-red/10 text-neon-red border border-neon-red/50 px-6 py-3 font-mono font-bold uppercase tracking-widest hover:bg-neon-red hover:text-bunker-950 transition-all clip-corner">
                <Zap size={16} />
                {t.sos.createBtn}
             </Link>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
          {/* Active Tickets */}
          <div className="bg-bunker-900 border border-neon-green/30 p-6 relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-4 opacity-20 group-hover:opacity-40 transition-opacity text-neon-green">
                    <Activity size={64} />
                </div>
                <div className="relative z-10">
                    <div className="text-xs font-mono text-slate-400 uppercase tracking-widest mb-2">{t.dashboard.activeTickets}</div>
                    <div className="text-3xl font-tech font-bold text-neon-green">
                        {loading ? '...' : activeCount}
                    </div>
                </div>
           </div>

           {/* Total Saved */}
           <div className="bg-bunker-900 border border-neon-cyan/30 p-6 relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-4 opacity-20 group-hover:opacity-40 transition-opacity text-neon-cyan">
                    <CreditCard size={64} />
                </div>
                <div className="relative z-10">
                    <div className="text-xs font-mono text-slate-400 uppercase tracking-widest mb-2">{t.dashboard.totalSaved}</div>
                    <div className="text-3xl font-tech font-bold text-neon-cyan">
                        {loading ? '...' : `₪${totalSaved.toFixed(2)}`}
                    </div>
                </div>
           </div>

           {/* Subscription Status */}
           <div className="bg-bunker-900 border border-neon-purple/30 p-6 relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-4 opacity-20 group-hover:opacity-40 transition-opacity text-neon-purple">
                    <ShieldCheck size={64} />
                </div>
                <div className="relative z-10">
                    <div className="text-xs font-mono text-slate-400 uppercase tracking-widest mb-2">{t.dashboard.subscription}</div>
                    <div className="text-3xl font-tech font-bold text-neon-purple">
                        {user?.subscriptions?.sos_business ? 'PRO' : 'BASIC'}
                    </div>
                </div>
           </div>
      </div>

      {/* Activity Log */}
      <div className="bg-bunker-900 border border-white/10 p-6 md:p-8 clip-corner">
        <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
            <Clock className="text-slate-400" size={20} />
            {t.dashboard.latestActivity}
        </h2>

        <div className="space-y-0">
            {loading ? (
                <div className="py-8 text-center text-neon-green animate-pulse font-mono text-sm">LOADING_DATA...</div>
            ) : latestTicket ? (
                <div className="flex items-center justify-between p-4 bg-bunker-950 border border-white/10 hover:border-neon-green/30 transition-all">
                    <div className="flex items-center gap-4">
                        <div className="bg-bunker-900 p-2 rounded-full border border-white/5">
                            {getStatusIcon(latestTicket.status)}
                        </div>
                        <div>
                            <div className="text-white font-bold text-sm md:text-base flex items-center gap-2">
                                <span className="text-neon-green font-mono">SOS-{latestTicket.id}</span>
                                <span className="text-slate-400 text-xs uppercase hidden md:inline-block">
                                    // {latestTicket.issue_type}
                                </span>
                            </div>
                            <div className="text-xs text-slate-500 font-mono mt-1">
                                {new Date(latestTicket.created_at).toLocaleDateString()} • {new Date(latestTicket.created_at).toLocaleTimeString()}
                            </div>
                        </div>
                    </div>

                    <div className="text-right">
                         <span className={`px-2 py-1 text-[10px] uppercase font-mono border rounded ${
                            latestTicket.status === 'resolved' ? 'text-neon-green border-neon-green/30 bg-neon-green/10' :
                            latestTicket.status === 'pending' ? 'text-yellow-500 border-yellow-500/30 bg-yellow-500/10' :
                            'text-slate-400 border-slate-500/30'
                         }`}>
                             {/* @ts-ignore */}
                             {t.sos.table.status_val[latestTicket.status] || latestTicket.status}
                         </span>
                    </div>
                </div>
            ) : (
                <div className="flex flex-col items-center justify-center py-12 text-slate-500 border border-dashed border-white/10 bg-bunker-950/50">
                    <Activity size={32} className="mb-4 opacity-50" />
                    <p className="font-mono text-sm">{t.dashboard.noActivity}</p>
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

