import React, { useState, useEffect } from 'react';
import { useLanguage } from '../lib/LanguageContext';
import { useAuth } from '../lib/AuthContext';
import { Siren, AlertTriangle, CheckCircle, Clock, Plus, Lock, XCircle, Loader, TrendingDown, TrendingUp, DollarSign } from 'lucide-react';
import { Link } from 'react-router-dom';
import { supabase } from '../lib/supabase';

export const SOS: React.FC = () => {
  const { t } = useLanguage();
  const { user } = useAuth();
  const [showForm, setShowForm] = useState(false);

  const [history, setHistory] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);

  // Financial Stats
  const [financials, setFinancials] = useState({
      debt: 0,
      savings: 0,
      marketTotal: 0
  });

  // Message Modal State
  const [messageModal, setMessageModal] = useState({ 
    isOpen: false, 
    title: '', 
    text: '', 
    isError: false 
  });

  const [formData, setFormData] = useState({
    issueType: 'hardware',
    description: '',
    urgency: 'high'
  });

  // Check Subscription
  const hasAccess = user?.subscriptions?.sos_business;

  // Helper to parse cost strings like "$100", "100.00", "100" to number
  const parseCost = (costStr: string | null): number => {
      if (!costStr || costStr === '-') return 0;
      // Remove non-numeric chars except dot and minus
      const cleaned = costStr.replace(/[^0-9.-]+/g, "");
      return parseFloat(cleaned) || 0;
  };

  const calculateFinancials = (tickets: any[]) => {
      let debt = 0;
      let savings = 0;
      let marketTotal = 0;

      tickets.forEach(ticket => {
          const ourCost = parseCost(ticket.cost);
          const marketCost = parseCost(ticket.market_cost);

          // Calculate Debt (Unpaid tickets with a valid cost)
          if (!ticket.is_paid && ourCost > 0 && ticket.status !== 'cancelled') {
              debt += ourCost;
          }

          // Calculate Savings (Only if we have both prices)
          if (ourCost > 0 && marketCost > 0) {
              savings += (marketCost - ourCost);
              marketTotal += marketCost;
          }
      });

      setFinancials({ debt, savings, marketTotal });
  };

  const fetchTickets = async () => {
    if (!user) return;
    setLoading(true);
    // Fetch tickets where user_id matches current user
    const { data, error } = await supabase
        .from('sos_tickets')
        .select('*')
        .eq('user_id', user.id)
        .order('created_at', { ascending: false });

    if (data) {
        setHistory(data);
        calculateFinancials(data);
    }
    if (error) console.error('Error fetching tickets', error);
    setLoading(false);
  };

  useEffect(() => {
    // We still fetch history so user can see old tickets, even if sub is cancelled, 
    // BUT the create button is hidden via UI check later.
    fetchTickets();
  }, [user]);

  const showMessage = (title: string, text: string, isError = true) => {
    setMessageModal({ isOpen: true, title, text, isError });
  };

  const closeMessage = () => setMessageModal(prev => ({ ...prev, isOpen: false }));

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;
    setSubmitting(true);

    try {
        const payload = {
            user_id: user.id,
            user_email: user.email,
            issue_type: formData.issueType,
            description: formData.description,
            urgency: formData.urgency,
            status: 'pending',
            cost: '-',
            market_cost: '-'
        };

        const { error } = await supabase.from('sos_tickets').insert([payload]);

        if (error) throw error;

        // Reset and refresh
        setFormData({ issueType: 'hardware', description: '', urgency: 'high' });
        setShowForm(false);
        fetchTickets();

        // Show Success Modal
        showMessage('SIGNAL RECEIVED', 'Your emergency ticket has been successfully logged into the system.', false);

    } catch (error: any) {
        console.error("Error creating ticket:", error);
        // Show Error Modal instead of alert
        showMessage('TRANSMISSION ERROR', `Failed to create ticket: ${error.message || 'Unknown error'}`, true);
    } finally {
        setSubmitting(false);
    }
  };

  const getStatusBadge = (status: string) => {
      // @ts-ignore
      const label = t.sos.table.status_val[status] || status;

      switch(status) {
          case 'resolved': return <span className="inline-flex items-center gap-1 text-neon-green bg-neon-green/10 px-2 py-0.5 text-[10px] font-mono uppercase border border-neon-green/20"><CheckCircle size={10} /> {label}</span>;
          case 'pending': return <span className="inline-flex items-center gap-1 text-yellow-500 bg-yellow-500/10 px-2 py-0.5 text-[10px] font-mono uppercase border border-yellow-500/20"><Clock size={10} /> {label}</span>;
          case 'in_progress': return <span className="inline-flex items-center gap-1 text-neon-cyan bg-neon-cyan/10 px-2 py-0.5 text-[10px] font-mono uppercase border border-neon-cyan/20"><Loader size={10} className="animate-spin"/> {label}</span>;
          case 'cancelled': return <span className="inline-flex items-center gap-1 text-red-500 bg-red-500/10 px-2 py-0.5 text-[10px] font-mono uppercase border border-red-500/20"><XCircle size={10} /> {label}</span>;
          default: return <span className="text-slate-400 text-xs">{label}</span>;
      }
  };

  return (
    <div className="container mx-auto px-4 md:px-6 py-12">
      <div className="bg-bunker-900 border border-white/10 p-8 md:p-12 mb-12 relative overflow-hidden clip-corner">
         <div className="absolute inset-0 bg-grid-pattern opacity-10"></div>
         <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-8">
            <div>
                <h1 className="text-3xl md:text-5xl font-tech font-bold text-white mb-2 flex items-center gap-3">
                    <Siren className="text-neon-red animate-pulse" />
                    {t.sos.title}
                </h1>
                <p className="text-slate-400 max-w-lg">{t.sos.subtitle}</p>
            </div>

            {/* Logic: Only show Trigger button if user has access. If not, maybe show "Subscription Required" or nothing */}
            {hasAccess ? (
                !showForm && (
                    <button 
                        onClick={() => setShowForm(true)}
                        className="group relative px-8 py-6 bg-neon-red text-bunker-950 font-bold font-tech text-xl tracking-widest clip-corner hover:bg-white transition-all shadow-[0_0_20px_rgba(255,0,60,0.4)]"
                    >
                        <span className="relative z-10 flex items-center gap-3">
                            <AlertTriangle className="animate-pulse" />
                            {t.sos.createBtn}
                        </span>
                    </button>
                )
            ) : (
                 <div className="flex items-center gap-3 px-6 py-4 border border-neon-red/30 bg-neon-red/5">
                    <Lock className="text-neon-red" size={20} />
                    <div className="text-left">
                        <div className="text-neon-red font-bold font-mono text-xs uppercase">ACCESS_DENIED</div>
                        <div className="text-slate-500 text-[10px]">Business Subscription Required</div>
                    </div>
                 </div>
            )}
         </div>
      </div>

      {/* Financial Intelligence Widget */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-12">
          {/* Debt Panel */}
          <div className="bg-bunker-950 border border-red-500/20 p-6 clip-corner relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                  <TrendingDown className="text-red-500" size={64} />
              </div>
              <h3 className="text-xs font-mono text-red-500 uppercase tracking-widest mb-2 flex items-center gap-2">
                  <span className="w-2 h-2 bg-red-500 rounded-full animate-pulse"></span>
                  {/* @ts-ignore */}
                  {t.sos.financials.debtTitle}
              </h3>
              <div className="text-4xl font-tech font-bold text-white mb-1">
                  {financials.debt > 0 ? `₪${financials.debt.toFixed(2)}` : '₪0.00'}
              </div>
              <p className="text-slate-500 text-xs font-mono">
                  {/* @ts-ignore */}
                  {financials.debt > 0 ? t.sos.financials.paymentRequired : t.sos.financials.allClear}
              </p>
          </div>

          {/* Savings Panel */}
          <div className="bg-bunker-900 border border-neon-green/20 p-6 clip-corner relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                  <TrendingUp className="text-neon-green" size={64} />
              </div>
              <h3 className="text-xs font-mono text-neon-green uppercase tracking-widest mb-2 flex items-center gap-2">
                  <DollarSign size={12} />
                  {/* @ts-ignore */}
                  {t.sos.financials.savingsTitle} ({t.sos.financials.lifetime})
              </h3>
              <div className="text-4xl font-tech font-bold text-white mb-1">
                  ₪{financials.savings.toFixed(2)}
              </div>
              <p className="text-slate-500 text-xs font-mono">
                  {/* @ts-ignore */}
                  {t.sos.financials.marketComparison} ({financials.marketTotal > 0 ? `₪${financials.marketTotal}` : '-'})
              </p>
          </div>
      </div>

      {showForm && hasAccess && (
        <div className="bg-bunker-950 border border-neon-red/30 p-6 md:p-8 mb-12 animate-fade-in-up">
            <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
                <Plus className="text-neon-red" />
                {t.sos.form.title}
            </h2>
            <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                    <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">{t.sos.form.issueType}</label>
                    <select 
                        className="w-full bg-bunker-900 border border-white/10 px-4 py-3 text-white focus:border-neon-red outline-none"
                        value={formData.issueType}
                        onChange={e => setFormData({...formData, issueType: e.target.value})}
                    >
                        <option value="hardware">Hardware Failure</option>
                        <option value="software">Software Bug</option>
                        <option value="network">Network/Connectivity</option>
                        <option value="security">Security Breach</option>
                        <option value="other">Other</option>
                    </select>
                </div>
                <div>
                    <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">{t.sos.form.urgency}</label>
                    <select 
                        className="w-full bg-bunker-900 border border-white/10 px-4 py-3 text-white focus:border-neon-red outline-none"
                        value={formData.urgency}
                        onChange={e => setFormData({...formData, urgency: e.target.value})}
                    >
                        <option value="low">Low (Next Business Day)</option>
                        <option value="medium">Medium (4 Hours)</option>
                        <option value="high">High (Immediate)</option>
                        <option value="critical">CRITICAL (System Down)</option>
                    </select>
                </div>
                <div className="md:col-span-2">
                    <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">{t.sos.form.desc}</label>
                    <textarea 
                        rows={4}
                        className="w-full bg-bunker-900 border border-white/10 px-4 py-3 text-white focus:border-neon-red outline-none"
                        value={formData.description}
                        onChange={e => setFormData({...formData, description: e.target.value})}
                        required
                    ></textarea>
                </div>
                <div className="md:col-span-2 flex justify-end gap-4">
                     <button 
                        type="button" 
                        onClick={() => setShowForm(false)}
                        className="px-6 py-3 border border-white/10 text-slate-400 hover:text-white font-mono uppercase text-xs"
                    >
                        Cancel
                    </button>
                    <button 
                        type="submit" 
                        disabled={submitting}
                        className="px-8 py-3 bg-neon-red text-bunker-950 font-bold font-mono uppercase text-xs hover:bg-white transition-colors disabled:opacity-50"
                    >
                        {submitting ? 'Sending...' : t.sos.form.submit}
                    </button>
                </div>
            </form>
        </div>
      )}

      <div>
        <h2 className="text-xl font-mono text-neon-green mb-6 uppercase tracking-widest flex items-center justify-between">
            {t.sos.historyTitle}
            {loading && <Loader className="animate-spin text-slate-500" size={16} />}
        </h2>
        <div className="bg-bunker-900 border border-white/5 overflow-x-auto">
            <table className="w-full text-left border-collapse">
                <thead>
                    <tr className="bg-bunker-950 text-slate-500 font-mono text-xs uppercase border-b border-white/10">
                        <th className="p-4">{t.sos.table.id}</th>
                        <th className="p-4">{t.sos.table.date}</th>
                        <th className="p-4">{t.sos.table.issue}</th>
                        <th className="p-4">{t.sos.table.status}</th>
                        {/* @ts-ignore */}
                        <th className="p-4 text-right">{t.sos.table.pricing}</th>
                    </tr>
                </thead>
                <tbody className="text-sm font-mono text-slate-300">
                    {history.map((item) => (
                        <tr key={item.id} className="border-b border-white/5 hover:bg-white/5 transition-colors">
                            <td className="p-4 text-neon-green">SOS-{item.id}</td>
                            <td className="p-4">{new Date(item.created_at).toLocaleDateString()}</td>
                            <td className="p-4 capitalize">
                                <div>{item.issue_type}</div>
                                {item.solution && (
                                    <div className="text-[10px] text-slate-500 mt-1 max-w-xs">{item.solution}</div>
                                )}
                            </td>
                            <td className="p-4">{getStatusBadge(item.status)}</td>
                            <td className="p-4 text-right">
                                <div className="flex flex-col items-end">
                                    <span className="text-white font-bold">{item.cost}</span>
                                    {item.market_cost && item.market_cost !== '-' && (
                                        <span className="text-[10px] text-slate-500 line-through decoration-red-500/50">
                                            {item.market_cost}
                                        </span>
                                    )}
                                    {item.is_paid 
                                        // @ts-ignore
                                        ? <span className="text-neon-green text-[9px] border border-neon-green/30 px-1 rounded mt-1">{t.sos.table.paid}</span>
                                        // @ts-ignore
                                        : (item.cost !== '-' && item.status !== 'cancelled') && <span className="text-red-500 text-[9px] border border-red-500/30 px-1 rounded mt-1 animate-pulse">{t.sos.table.unpaid}</span>
                                    }
                                </div>
                            </td>
                        </tr>
                    ))}
                    {!loading && history.length === 0 && (
                        <tr>
                            <td colSpan={5} className="p-8 text-center text-slate-500">NO_RECORDS_FOUND</td>
                        </tr>
                    )}
                </tbody>
            </table>
        </div>
      </div>

      {/* Message Modal */}
      {messageModal.isOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fade-in">
             <div className={`bg-bunker-900 border ${messageModal.isError ? 'border-red-500/50' : 'border-neon-green/50'} p-8 max-w-sm w-full shadow-[0_0_50px_rgba(0,0,0,0.5)] clip-corner relative animate-fade-in-up`}>
                 <div className="flex items-start gap-4 mb-6">
                    <div className={`p-3 border rounded-full shrink-0 ${messageModal.isError ? 'bg-red-500/10 border-red-500/30 text-red-500' : 'bg-neon-green/10 border-neon-green/30 text-neon-green'}`}>
                        {messageModal.isError ? <AlertTriangle size={24} /> : <CheckCircle size={24} />}
                    </div>
                    <div>
                        <h3 className={`text-xl font-tech font-bold uppercase mb-2 ${messageModal.isError ? 'text-red-500' : 'text-neon-green'}`}>
                            {messageModal.title}
                        </h3>
                        <p className="text-slate-300 font-mono text-sm leading-relaxed">
                            {messageModal.text}
                        </p>
                    </div>
                 </div>

                 <button 
                    onClick={closeMessage} 
                    className={`w-full py-3 font-bold uppercase tracking-widest text-xs border transition-all ${
                        messageModal.isError 
                        ? 'bg-red-500 text-white border-red-500 hover:bg-white hover:text-red-500' 
                        : 'bg-neon-green text-bunker-950 border-neon-green hover:bg-white'
                    }`}
                 >
                    ACKNOWLEDGE
                 </button>
             </div>
        </div>
      )}

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ArrowRight, Zap, Siren, ShoppingCart, X, CheckCircle, AlertTriangle } from 'lucide-react';
import { Link, useSearchParams, useNavigate } from 'react-router-dom';
import { useLanguage } from '../lib/LanguageContext';
import { useAuth } from '../lib/AuthContext';
import { SERVICES_LIST } from '../constants';
import { SEO } from '../components/SEO';
import { supabase } from '../lib/supabase';

export const Services: React.FC = () => {
  const { t, language } = useLanguage();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const [activeTab, setActiveTab] = useState<'all' | 'ai' | 'web' | 'hardware' | 'consulting' | 'sos'>('all');

  // Modal State
  const [orderModal, setOrderModal] = useState({
      isOpen: false,
      serviceId: '',
      serviceName: ''
  });
  const [orderForm, setOrderForm] = useState({
      projectName: '',
      description: '',
      contact: ''
  });
  const [submitting, setSubmitting] = useState(false);
  const [messageModal, setMessageModal] = useState({ isOpen: false, title: '', text: '', isError: false });


  useEffect(() => {
    const category = searchParams.get('category');
    if (category && ['ai', 'web', 'hardware', 'consulting', 'sos'].includes(category)) {
      setActiveTab(category as any);
    } else {
      setActiveTab('all');
    }
  }, [searchParams]);

  const filteredServices = activeTab === 'all' 
    ? SERVICES_LIST 
    : SERVICES_LIST.filter(s => s.category === activeTab);

  const handleOrderClick = (serviceId: string, serviceTitle: string) => {
      if (!user) {
          navigate('/login');
          return;
      }
      setOrderModal({ isOpen: true, serviceId, serviceName: serviceTitle });
  };

  const handleOrderSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!user) return;
      setSubmitting(true);

      try {
          const { error } = await supabase.from('service_orders').insert([{
              user_id: user.id,
              user_email: user.email,
              service_type: orderModal.serviceId, // simplified type mapping
              project_name: orderForm.projectName || orderModal.serviceName,
              description: orderForm.description,
              contact_info: orderForm.contact,
              status: 'pending',
              price: '-',
              eta: null
          }]);

          if (error) throw error;

          setOrderModal({ ...orderModal, isOpen: false });
          setOrderForm({ projectName: '', description: '', contact: '' });
          setMessageModal({
              isOpen: true,
              title: 'ORDER PLACED',
              text: 'Your order has been received. Check your Dashboard for updates.',
              isError: false
          });

      } catch (err: any) {
           setMessageModal({
              isOpen: true,
              title: 'ERROR',
              text: err.message,
              isError: true
          });
      } finally {
          setSubmitting(false);
      }
  };

  return (
    <div className="py-20 container mx-auto px-4 md:px-6 relative">
      <SEO pageKey="services" />
      <div className="text-center mb-16 relative">
         <div className="absolute top-1/2 left-0 w-full h-px bg-white/5 -z-10"></div>
         <div className="inline-block bg-bunker-950 px-6 relative z-10">
            <h1 className="text-4xl md:text-6xl font-tech font-bold text-white mb-4 tracking-tight">
                <span className="text-neon-green">/</span> {t.services.title}
            </h1>
            <p className="text-slate-400 max-w-xl mx-auto font-mono text-sm text-neon-green/70">
            {t.services.subtitle}
            </p>
        </div>
      </div>

      <div className="flex justify-center mb-16 flex-wrap gap-3 md:gap-4">
        {[
          { id: 'all', label: t.services.categories.all },
          { id: 'ai', label: t.services.categories.ai },
          { id: 'web', label: t.services.categories.web },
          { id: 'hardware', label: t.services.categories.hardware },
          { id: 'consulting', label: t.services.categories.consulting },
          { id: 'sos', label: t.services.categories.sos, icon: <Siren size={14} className="mr-2 inline" /> },
        ].map((tab) => (
          <button
            key={tab.id}
            onClick={() => {
              setActiveTab(tab.id as any);
              const newUrl = tab.id === 'all' ? '/services' : `/services?category=${tab.id}`;
              window.history.pushState({}, '', newUrl);
            }}
            className={`px-4 py-2 md:px-6 md:py-3 font-mono text-[10px] md:text-xs uppercase tracking-widest clip-corner transition-all border flex items-center ${
              activeTab === tab.id 
                ? 'bg-neon-green text-bunker-950 border-neon-green font-bold' 
                : 'bg-transparent text-slate-400 border-white/10 hover:border-white/30 hover:text-white'
            }`}
          >
            {/* @ts-ignore */}
            {tab.icon}
            {tab.label}
          </button>
        ))}
      </div>

      {/* FORCE GRID-COLS-2 MINIMUM */}
      <div className="grid grid-cols-2 md:grid-cols-3 gap-4 md:gap-6 animate-fade-in-up">
        {filteredServices.map((service, idx) => {
          // @ts-ignore
          const serviceInfo = t.services.items[service.id] || { title: service.id, desc: 'Service description...' };
          const categoryColor = service.category === 'sos' ? 'text-neon-red border-neon-red/30' : 'text-neon-green border-neon-green/30';
          const hoverBorder = service.category === 'sos' ? 'group-hover:border-neon-red' : 'group-hover:border-neon-green';

          return (
            <div key={idx} className={`group bg-bunker-900/50 relative p-4 md:p-8 border border-white/5 ${hoverBorder} transition-all flex flex-col hover:bg-bunker-900`}>
                <div className="absolute top-0 right-0 p-2 md:p-4 opacity-0 group-hover:opacity-100 transition-opacity hidden sm:block">
                    <Zap size={16} className={service.category === 'sos' ? 'text-neon-red' : 'text-neon-green'} />
                </div>

                <div className="mb-4 md:mb-6 flex flex-col items-start gap-3">
                    <div className={`w-10 h-10 md:w-14 md:h-14 bg-bunker-950 border flex items-center justify-center shadow-[0_0_20px_rgba(0,0,0,0.5)] clip-corner shrink-0 ${categoryColor}`}>
                        <service.icon size={20} className="md:w-7 md:h-7" />
                    </div>
                </div>

                <h3 className={`text-sm md:text-2xl font-bold text-white mb-2 md:mb-3 transition-colors leading-tight ${service.category === 'sos' ? 'group-hover:text-neon-red' : 'group-hover:text-neon-green'}`}>
                    {serviceInfo.title}
                </h3>

                <p className="text-xs md:text-sm text-slate-400 mb-4 md:mb-8 flex-grow leading-relaxed font-light line-clamp-3 md:line-clamp-none">
                    {serviceInfo.desc}
                </p>

                <div className="mt-auto pt-4 md:pt-6 border-t border-white/5 flex items-center justify-between gap-2">
                    <span className="text-neon-cyan font-mono text-[10px] md:text-xs">
                        {/* @ts-ignore */}
                        {serviceInfo.price || t.services.price_individual}
                    </span>

                    {service.category !== 'sos' && (
                        <button 
                            onClick={() => handleOrderClick(service.id, serviceInfo.title)}
                            className="flex items-center gap-2 px-3 py-2 bg-neon-green/10 border border-neon-green/30 text-neon-green hover:bg-neon-green hover:text-bunker-950 font-mono text-[10px] uppercase font-bold transition-all rounded"
                        >
                            <ShoppingCart size={12} />
                            {/* @ts-ignore */}
                            {t.services.orderBtn}
                        </button>
                    )}

                    {service.category === 'sos' && (
                         <Link to="/sos" className="w-8 h-8 md:w-10 md:h-10 flex items-center justify-center border border-white/10 text-slate-400 hover:text-bunker-950 transition-all clip-corner hover:bg-neon-red hover:border-neon-red">
                            <ArrowRight size={14} className={`md:w-4 md:h-4 ${language === 'he' ? 'rotate-180' : ''}`} />
                         </Link>
                    )}
                </div>
            </div>
          );
        })}
      </div>

      {/* Order Modal */}
      {orderModal.isOpen && (
          <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-bunker-950/90 backdrop-blur-sm animate-fade-in">
              <div className="bg-bunker-900 border border-neon-green/30 w-full max-w-lg clip-corner shadow-2xl relative animate-fade-in-up">
                  <div className="p-6 border-b border-white/10 flex justify-between items-center">
                      <h3 className="text-xl font-tech font-bold text-white flex items-center gap-2">
                          <ShoppingCart className="text-neon-green" size={20} />
                          {/* @ts-ignore */}
                          {t.services.modal.title}
                      </h3>
                      <button onClick={() => setOrderModal({...orderModal, isOpen: false})} className="text-slate-400 hover:text-white">
                          <X size={20} />
                      </button>
                  </div>

                  <form onSubmit={handleOrderSubmit} className="p-6 space-y-4">
                       <div className="bg-bunker-950 p-3 border border-white/10 mb-4 text-sm text-neon-green font-mono">
                           SERVICE: {orderModal.serviceName}
                       </div>

                       <div>
                           {/* @ts-ignore */}
                           <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">{t.services.modal.projectName}</label>
                           <input 
                                type="text" 
                                required
                                value={orderForm.projectName}
                                onChange={e => setOrderForm({...orderForm, projectName: e.target.value})}
                                className="w-full bg-bunker-950 border border-white/10 px-4 py-3 text-white focus:border-neon-green outline-none"
                                placeholder={orderModal.serviceName}
                           />
                       </div>

                       <div>
                           {/* @ts-ignore */}
                           <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">{t.services.modal.desc}</label>
                           <textarea 
                                rows={3}
                                required
                                value={orderForm.description}
                                onChange={e => setOrderForm({...orderForm, description: e.target.value})}
                                className="w-full bg-bunker-950 border border-white/10 px-4 py-3 text-white focus:border-neon-green outline-none"
                           ></textarea>
                       </div>

                       <div>
                           {/* @ts-ignore */}
                           <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">{t.services.modal.contact}</label>
                           <input 
                                type="text" 
                                required
                                value={orderForm.contact}
                                onChange={e => setOrderForm({...orderForm, contact: e.target.value})}
                                className="w-full bg-bunker-950 border border-white/10 px-4 py-3 text-white focus:border-neon-green outline-none"
                                placeholder="@username or +972..."
                           />
                       </div>

                       <div className="flex gap-3 pt-4 border-t border-white/10">
                            {/* @ts-ignore */}
                            <button type="button" onClick={() => setOrderModal({...orderModal, isOpen: false})} className="flex-1 py-3 border border-white/10 text-slate-400 hover:text-white font-mono uppercase text-xs font-bold">{t.services.modal.cancel}</button>
                            {/* @ts-ignore */}
                            <button type="submit" disabled={submitting} className="flex-1 py-3 bg-neon-green text-bunker-950 font-mono uppercase text-xs font-bold hover:bg-white transition-colors flex items-center justify-center gap-2">{submitting ? '...' : t.services.modal.submit}</button>
                       </div>
                  </form>
              </div>
          </div>
      )}

      {/* Message Modal */}
      {messageModal.isOpen && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-fade-in">
             <div className={`bg-bunker-900 border ${messageModal.isError ? 'border-red-500/50' : 'border-neon-green/50'} p-8 max-w-sm w-full shadow-[0_0_50px_rgba(0,0,0,0.5)] clip-corner relative animate-fade-in-up`}>
                 <div className="flex items-start gap-4 mb-6">
                    <div className={`p-3 border rounded-full shrink-0 ${messageModal.isError ? 'bg-red-500/10 border-red-500/30 text-red-500' : 'bg-neon-green/10 border-neon-green/30 text-neon-green'}`}>
                        {messageModal.isError ? <AlertTriangle size={24} /> : <CheckCircle size={24} />}
                    </div>
                    <div>
                        <h3 className={`text-xl font-tech font-bold uppercase mb-2 ${messageModal.isError ? 'text-red-500' : 'text-neon-green'}`}>
                            {messageModal.title}
                        </h3>
                        <p className="text-slate-300 font-mono text-sm leading-relaxed">
                            {messageModal.text}
                        </p>
                    </div>
                 </div>

                 <button 
                    onClick={() => setMessageModal({...messageModal, isOpen: false})} 
                    className={`w-full py-3 font-bold uppercase tracking-widest text-xs border transition-all ${
                        messageModal.isError 
                        ? 'bg-red-500 text-white border-red-500 hover:bg-white hover:text-red-500' 
                        : 'bg-neon-green text-bunker-950 border-neon-green hover:bg-white'
                    }`}
                 >
                    ACKNOWLEDGE
                 </button>
             </div>
        </div>
      )}

    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useLanguage } from '../lib/LanguageContext';
import { useAuth } from '../lib/AuthContext';
import { supabase } from '../lib/supabase';
import { Activity, CreditCard, ShieldCheck, Clock, Zap, CheckCircle, AlertTriangle, Loader, XCircle, FileText, ChevronDown, ChevronUp } from 'lucide-react';
import { Link } from 'react-router-dom';

export const Dashboard: React.FC = () => {
  const { t } = useLanguage();
  const { user } = useAuth();

  const [loading, setLoading] = useState(true);
  const [activeCount, setActiveCount] = useState(0);
  const [totalSaved, setTotalSaved] = useState(0);

  // Mixed activity list
  const [activityFeed, setActivityFeed] = useState<any[]>([]);
  const [expandedId, setExpandedId] = useState<string | null>(null);

  // Helper to parse cost strings
  const parseCost = (costStr: string | null): number => {
      if (!costStr || costStr === '-') return 0;
      const cleaned = costStr.replace(/[^0-9.-]+/g, "");
      return parseFloat(cleaned) || 0;
  };

  useEffect(() => {
    const fetchDashboardData = async () => {
        if (!user) return;
        setLoading(true);

        // 1. Fetch SOS Tickets
        const { data: tickets, error: ticketsError } = await supabase
            .from('sos_tickets')
            .select('*')
            .eq('user_id', user.id);

        // 2. Fetch Service Orders
        const { data: orders, error: ordersError } = await supabase
            .from('service_orders')
            .select('*')
            .eq('user_id', user.id);

        if (ticketsError) console.error("Error tickets:", ticketsError);
        if (ordersError) console.error("Error orders:", ordersError);

        const safeTickets = tickets || [];
        const safeOrders = orders || [];

        // --- Logic: Stats ---
        // Active Count (Both types)
        const activeTickets = safeTickets.filter(t => t.status === 'pending' || t.status === 'in_progress').length;
        const activeOrders = safeOrders.filter(o => o.status === 'pending' || o.status === 'in_progress').length;
        setActiveCount(activeTickets + activeOrders);

        // Savings (Only from SOS for now, maybe orders imply value later)
        let savings = 0;
        safeTickets.forEach(t => {
            const ourCost = parseCost(t.cost);
            const marketCost = parseCost(t.market_cost);
            if (ourCost > 0 && marketCost > 0) savings += (marketCost - ourCost);
        });
        setTotalSaved(savings);

        // --- Logic: Activity Feed ---
        // Merge and sort by date desc
        const merged = [
            ...safeTickets.map(t => ({ ...t, type: 'sos', sortDate: new Date(t.created_at) })),
            ...safeOrders.map(o => ({ ...o, type: 'order', sortDate: new Date(o.created_at) }))
        ].sort((a, b) => b.sortDate.getTime() - a.sortDate.getTime());

        setActivityFeed(merged);
        setLoading(false);
    };

    fetchDashboardData();
  }, [user]);

  const toggleExpand = (id: string) => {
      setExpandedId(expandedId === id ? null : id);
  };

  const getStatusIcon = (status: string) => {
      switch(status) {
          case 'resolved': 
          case 'completed': return <CheckCircle size={20} className="text-neon-green" />;
          case 'pending': return <Clock size={20} className="text-yellow-500" />;
          case 'in_progress': return <Loader size={20} className="text-neon-cyan animate-spin" />;
          case 'cancelled': return <XCircle size={20} className="text-red-500" />;
          default: return <Activity size={20} className="text-slate-400" />;
      }
  };

  return (
    <div className="container mx-auto px-4 md:px-6 py-12">
      {/* Header */}
      <div className="mb-10 flex flex-col md:flex-row justify-between items-start md:items-end border-b border-white/10 pb-6">
        <div>
            <div className="text-[10px] font-mono text-neon-green mb-2 animate-pulse">SYSTEM_ONLINE</div>
            <h1 className="text-3xl md:text-5xl font-tech font-bold text-white">{t.dashboard.welcome}</h1>
        </div>
        <div className="mt-4 md:mt-0 flex gap-2">
             <Link to="/services" className="flex items-center gap-2 bg-neon-green/10 text-neon-green border border-neon-green/50 px-6 py-3 font-mono font-bold uppercase tracking-widest hover:bg-neon-green hover:text-bunker-950 transition-all clip-corner text-xs">
                <FileText size={16} />
                {/* @ts-ignore */}
                {t.services.orderBtn}
             </Link>
             <Link to="/sos" className="flex items-center gap-2 bg-neon-red/10 text-neon-red border border-neon-red/50 px-6 py-3 font-mono font-bold uppercase tracking-widest hover:bg-neon-red hover:text-bunker-950 transition-all clip-corner text-xs">
                <Zap size={16} />
                {t.sos.createBtn}
             </Link>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
          {/* Active Tickets */}
          <div className="bg-bunker-900 border border-neon-green/30 p-6 relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-4 opacity-20 group-hover:opacity-40 transition-opacity text-neon-green">
                    <Activity size={64} />
                </div>
                <div className="relative z-10">
                    <div className="text-xs font-mono text-slate-400 uppercase tracking-widest mb-2">{t.dashboard.activeTickets}</div>
                    <div className="text-3xl font-tech font-bold text-neon-green">
                        {loading ? '...' : activeCount}
                    </div>
                </div>
           </div>

           {/* Total Saved */}
           <div className="bg-bunker-900 border border-neon-cyan/30 p-6 relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-4 opacity-20 group-hover:opacity-40 transition-opacity text-neon-cyan">
                    <CreditCard size={64} />
                </div>
                <div className="relative z-10">
                    <div className="text-xs font-mono text-slate-400 uppercase tracking-widest mb-2">{t.dashboard.totalSaved}</div>
                    <div className="text-3xl font-tech font-bold text-neon-cyan">
                        {loading ? '...' : `₪${totalSaved.toFixed(2)}`}
                    </div>
                </div>
           </div>

           {/* Subscription Status */}
           <div className="bg-bunker-900 border border-neon-purple/30 p-6 relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-4 opacity-20 group-hover:opacity-40 transition-opacity text-neon-purple">
                    <ShieldCheck size={64} />
                </div>
                <div className="relative z-10">
                    <div className="text-xs font-mono text-slate-400 uppercase tracking-widest mb-2">{t.dashboard.subscription}</div>
                    <div className="text-3xl font-tech font-bold text-neon-purple">
                        {user?.subscriptions?.sos_business ? 'PRO' : 'BASIC'}
                    </div>
                </div>
           </div>
      </div>

      {/* Activity Log */}
      <div className="bg-bunker-900 border border-white/10 p-6 md:p-8 clip-corner min-h-[400px]">
        <h2 className="text-xl font-bold text-white mb-6 flex items-center gap-2">
            <Clock className="text-slate-400" size={20} />
            {t.dashboard.latestActivity}
        </h2>

        <div className="space-y-4">
            {loading ? (
                <div className="py-8 text-center text-neon-green animate-pulse font-mono text-sm">LOADING_DATA...</div>
            ) : activityFeed.length > 0 ? (
                activityFeed.map((item) => {
                    const isSOS = item.type === 'sos';
                    const uniqueId = isSOS ? `sos-${item.id}` : `order-${item.id}`;
                    const isExpanded = expandedId === uniqueId;

                    return (
                        <div key={uniqueId} className={`bg-bunker-950 border transition-all ${isSOS ? 'border-neon-red/20 hover:border-neon-red/50' : 'border-neon-green/20 hover:border-neon-green/50'}`}>
                             {/* Summary Row */}
                             <div 
                                onClick={() => toggleExpand(uniqueId)}
                                className="flex items-center justify-between p-4 cursor-pointer"
                             >
                                <div className="flex items-center gap-4">
                                    <div className={`p-2 rounded-full border border-white/5 ${isSOS ? 'bg-neon-red/5 text-neon-red' : 'bg-neon-green/5 text-neon-green'}`}>
                                        {getStatusIcon(item.status)}
                                    </div>
                                    <div>
                                        <div className="text-white font-bold text-sm md:text-base flex items-center gap-2">
                                            <span className={`font-mono ${isSOS ? 'text-neon-red' : 'text-neon-green'}`}>
                                                {isSOS ? `SOS-${item.id}` : `PRJ-${item.id}`}
                                            </span>
                                            <span className="text-slate-400 text-xs uppercase hidden md:inline-block">
                                                // {isSOS ? item.issue_type : item.service_type}
                                            </span>
                                        </div>
                                        <div className="text-xs text-slate-500 font-mono mt-1">
                                            {isSOS ? (item.description?.substring(0, 40) + '...') : item.project_name}
                                        </div>
                                    </div>
                                </div>

                                <div className="flex items-center gap-4">
                                    <div className="text-right hidden sm:block">
                                        <div className="text-xs text-slate-500 font-mono">{new Date(item.created_at).toLocaleDateString()}</div>
                                        <div className={`text-[10px] uppercase font-mono ${isSOS ? 'text-neon-red' : 'text-neon-green'}`}>
                                            {item.status}
                                        </div>
                                    </div>
                                    {isExpanded ? <ChevronUp size={16} className="text-slate-500"/> : <ChevronDown size={16} className="text-slate-500"/>}
                                </div>
                             </div>

                             {/* Expanded Details */}
                             {isExpanded && (
                                 <div className="p-4 border-t border-white/5 bg-white/5 text-sm font-mono space-y-3 animate-fade-in">
                                     <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                         <div>
                                             <span className="block text-[10px] text-slate-500 uppercase tracking-widest mb-1">{isSOS ? 'Issue Description' : t.projects.desc}</span>
                                             <p className="text-slate-300">{item.description}</p>
                                         </div>
                                         {!isSOS && (
                                            <div>
                                                <span className="block text-[10px] text-slate-500 uppercase tracking-widest mb-1">{t.projects.contact}</span>
                                                <p className="text-slate-300">{item.contact_info || '-'}</p>
                                            </div>
                                         )}
                                     </div>

                                     <div className="grid grid-cols-2 md:grid-cols-4 gap-4 pt-3 border-t border-white/5">
                                         <div>
                                             <span className="block text-[10px] text-slate-500 uppercase tracking-widest mb-1">{isSOS ? t.admin.sos_table.cost : t.projects.price}</span>
                                             <span className="text-white font-bold">{item.price || item.cost || '-'}</span>
                                         </div>
                                         {!isSOS && (
                                             <div>
                                                <span className="block text-[10px] text-slate-500 uppercase tracking-widest mb-1">{t.projects.eta}</span>
                                                <span className="text-neon-cyan">{item.eta ? new Date(item.eta).toLocaleDateString() : 'TBD'}</span>
                                             </div>
                                         )}
                                         {/* For SOS we show solution */}
                                         {isSOS && item.solution && (
                                             <div className="col-span-2">
                                                 <span className="block text-[10px] text-slate-500 uppercase tracking-widest mb-1">Resolution</span>
                                                 <span className="text-neon-green">{item.solution}</span>
                                             </div>
                                         )}
                                     </div>
                                 </div>
                             )}
                        </div>
                    );
                })
            ) : (
                <div className="flex flex-col items-center justify-center py-12 text-slate-500 border border-dashed border-white/10 bg-bunker-950/50">
                    <Activity size={32} className="mb-4 opacity-50" />
                    <p className="font-mono text-sm">{t.dashboard.noActivity}</p>
                </div>
            )}
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useLanguage } from '../lib/LanguageContext';
import { supabase } from '../lib/supabase';
import { Users, Database, ShieldAlert, Terminal, Trash2, Edit, Loader, Plus, X, Save, Lock, Mail, Building, ToggleLeft, ToggleRight, AlertTriangle, Siren, DollarSign, Calendar, CheckSquare, FileText } from 'lucide-react';

// ... (previous interfaces) ...
interface AdminFormData {
  email: string;
  password: string;
  role: string;
  business_name: string;
  subscriptions: {
    [key: string]: any;
  };
}

interface SosTicketData {
    id: number | null;
    status: string;
    issue_type: string;
    urgency: string;
    description: string;
    solution: string;
    cost: string;
    market_cost: string;
    is_paid: boolean;
    created_at: string;
}

interface ProjectData {
    id: number | null;
    status: string;
    project_name: string;
    description: string;
    price: string;
    eta: string;
    completed_at: string;
    contact_info: string;
}

export const Admin: React.FC = () => {
  const { t } = useLanguage();

  // Data States
  const [users, setUsers] = useState<any[]>([]);
  const [tickets, setTickets] = useState<any[]>([]);
  const [projects, setProjects] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  // UI States
  const [activeTab, setActiveTab] = useState<'users' | 'sos' | 'projects'>('users');

  // Modal States
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isSosModalOpen, setIsSosModalOpen] = useState(false);
  const [isProjectModalOpen, setIsProjectModalOpen] = useState(false);

  // Message Modal
  const [messageModal, setMessageModal] = useState({ 
    isOpen: false, 
    title: '', 
    text: '', 
    isError: false 
  });

  // Editing States
  const [editingUserId, setEditingUserId] = useState<number | null>(null);
  const [editingTicketId, setEditingTicketId] = useState<number | null>(null);
  const [editingProjectId, setEditingProjectId] = useState<number | null>(null);

  // Forms
  const [userFormData, setUserFormData] = useState<AdminFormData>({
    email: '',
    password: '',
    role: 'CLIENT',
    business_name: '',
    subscriptions: { sos_business: false }
  });

  const [sosFormData, setSosFormData] = useState<SosTicketData>({
      id: null,
      status: 'pending',
      issue_type: '',
      urgency: '',
      description: '',
      solution: '',
      cost: '-',
      market_cost: '-',
      is_paid: false,
      created_at: ''
  });

  const [projectFormData, setProjectFormData] = useState<ProjectData>({
      id: null,
      status: 'pending',
      project_name: '',
      description: '',
      price: '-',
      eta: '',
      completed_at: '',
      contact_info: ''
  });

  const fetchUsers = async () => {
    const { data, error } = await supabase.from('app_users').select('*').order('id', { ascending: true });
    if (error) console.error("Error fetching users:", error);
    if (data) setUsers(data);
  };

  const fetchTickets = async () => {
    const { data, error } = await supabase
        .from('sos_tickets')
        .select('*')
        .order('created_at', { ascending: false });
    if (error) console.error("Error fetching tickets:", error);
    if (data) setTickets(data);
  };

  const fetchProjects = async () => {
      const { data, error } = await supabase
        .from('service_orders')
        .select('*')
        .order('created_at', { ascending: false });
      if (error) console.error("Error fetching projects:", error);
      if (data) setProjects(data);
  };

  const fetchData = async () => {
    setLoading(true);
    await Promise.all([fetchUsers(), fetchTickets(), fetchProjects()]);
    setLoading(false);
  };

  useEffect(() => {
    fetchData();
  }, []);

  // --- Message Helper ---
  const showMessage = (title: string, text: string, isError = true) => {
    setMessageModal({ isOpen: true, title, text, isError });
  };
  const closeMessage = () => setMessageModal(prev => ({ ...prev, isOpen: false }));


  // --- USER Logic (Keep existing) ---
  const handleOpenUserModal = (user?: any) => {
    if (user) {
        setEditingUserId(user.id);
        let userSubs = user.subscriptions;
        if (typeof userSubs === 'string') {
            try { userSubs = JSON.parse(userSubs); } catch(e) { console.error("Error parsing subs", e); }
        }
        if (!userSubs) userSubs = { sos_business: false };

        setUserFormData({
            email: user.email,
            password: user.password,
            role: user.role,
            business_name: user.business_name || '',
            subscriptions: userSubs
        });
    } else {
        setEditingUserId(null);
        setUserFormData({
            email: '',
            password: '',
            role: 'CLIENT',
            business_name: '',
            subscriptions: { sos_business: false }
        });
    }
    setIsUserModalOpen(true);
  };

  const handleDeleteUser = async (id: number) => {
    if (window.confirm(t.admin.actions.confirmDelete)) {
        const { error } = await supabase.from('app_users').delete().eq('id', id);
        if (error) showMessage("DELETE ERROR", error.message, true);
        else fetchUsers();
    }
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    const basePayload = {
        email: userFormData.email,
        password: userFormData.password,
        role: userFormData.role,
        business_name: userFormData.business_name,
    };
    const fullPayload = { ...basePayload, subscriptions: userFormData.subscriptions };

    try {
        let result;
        if (editingUserId) {
            result = await supabase.from('app_users').update(fullPayload).eq('id', editingUserId).select();
        } else {
            result = await supabase.from('app_users').insert([fullPayload]).select();
        }

        if (result.error) throw result.error;
        setIsUserModalOpen(false);
        fetchUsers();
    } catch (error: any) {
        if (error.message?.includes('subscriptions')) {
            try {
                if (editingUserId) await supabase.from('app_users').update(basePayload).eq('id', editingUserId);
                else await supabase.from('app_users').insert([basePayload]);
                setIsUserModalOpen(false);
                fetchUsers();
                showMessage("PARTIAL SAVE", "User saved without subscriptions (DB column missing).", true);
                return;
            } catch(e) {}
        }
        showMessage("SAVE ERROR", error.message || 'Unknown error', true);
    }
  };

  const toggleSubscription = (key: string) => {
      setUserFormData(prev => ({
          ...prev,
          subscriptions: { ...prev.subscriptions, [key]: !prev.subscriptions[key] }
      }));
  };

  // --- SOS Logic (Keep existing) ---
  const handleOpenSosModal = (ticket: any) => {
      setEditingTicketId(ticket.id);
      setSosFormData({
          id: ticket.id,
          status: ticket.status || 'pending',
          issue_type: ticket.issue_type,
          urgency: ticket.urgency,
          description: ticket.description,
          solution: ticket.solution || '',
          cost: ticket.cost || '-',
          market_cost: ticket.market_cost || '-',
          is_paid: ticket.is_paid || false,
          created_at: ticket.created_at
      });
      setIsSosModalOpen(true);
  };

  const handleDeleteTicket = async (id: number) => {
      if(window.confirm(t.admin.actions.confirmDelete)) {
          const { error } = await supabase.from('sos_tickets').delete().eq('id', id);
          if (error) showMessage("DELETE ERROR", error.message, true);
          else fetchTickets();
      }
  };

  const handleSaveTicket = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!editingTicketId) return;

      const { error } = await supabase
        .from('sos_tickets')
        .update({
            status: sosFormData.status,
            cost: sosFormData.cost,
            market_cost: sosFormData.market_cost,
            solution: sosFormData.solution,
            is_paid: sosFormData.is_paid,
            issue_type: sosFormData.issue_type,
            urgency: sosFormData.urgency,
            description: sosFormData.description,
            created_at: sosFormData.created_at
        })
        .eq('id', editingTicketId);

      if (error) {
          showMessage("SAVE ERROR", error.message, true);
      } else {
          setIsSosModalOpen(false);
          fetchTickets();
      }
  };

  // --- Projects Logic ---
  const handleOpenProjectModal = (project: any) => {
      setEditingProjectId(project.id);
      setProjectFormData({
          id: project.id,
          status: project.status || 'pending',
          project_name: project.project_name,
          description: project.description,
          price: project.price || '-',
          eta: project.eta ? new Date(project.eta).toISOString().slice(0, 16) : '',
          completed_at: project.completed_at ? new Date(project.completed_at).toISOString().slice(0, 16) : '',
          contact_info: project.contact_info || ''
      });
      setIsProjectModalOpen(true);
  };

  const handleDeleteProject = async (id: number) => {
      if(window.confirm(t.admin.actions.confirmDelete)) {
          const { error } = await supabase.from('service_orders').delete().eq('id', id);
          if (error) showMessage("DELETE ERROR", error.message, true);
          else fetchProjects();
      }
  };

  const handleSaveProject = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!editingProjectId) return;

      const { error } = await supabase
        .from('service_orders')
        .update({
            status: projectFormData.status,
            project_name: projectFormData.project_name,
            description: projectFormData.description,
            price: projectFormData.price,
            eta: projectFormData.eta || null,
            completed_at: projectFormData.completed_at || null,
            contact_info: projectFormData.contact_info
        })
        .eq('id', editingProjectId);

      if (error) {
          showMessage("SAVE ERROR", error.message, true);
      } else {
          setIsProjectModalOpen(false);
          fetchProjects();
      }
  };


  return (
    <div className="container mx-auto px-4 md:px-6 py-12 relative min-h-screen">
      <div className="flex items-center gap-4 mb-10 border-b border-neon-red/30 pb-6">
        <div className="p-3 bg-neon-red/10 border border-neon-red/30 rounded">
             <ShieldAlert className="text-neon-red" size={32} />
        </div>
        <div>
            <h1 className="text-3xl font-tech font-bold text-white uppercase tracking-wider">{t.admin.title}</h1>
            <p className="text-neon-red font-mono text-xs">RESTRICTED AREA // LEVEL 5 CLEARANCE</p>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex gap-1 mb-8 overflow-x-auto">
          <button 
            onClick={() => setActiveTab('users')}
            className={`px-6 py-3 font-mono uppercase font-bold text-sm transition-all clip-corner-br ${
                activeTab === 'users' 
                ? 'bg-neon-green text-bunker-950' 
                : 'bg-bunker-900 text-slate-500 border border-white/10 hover:text-white'
            }`}
          >
              {t.admin.tabs.users}
          </button>
          <button 
            onClick={() => setActiveTab('sos')}
            className={`px-6 py-3 font-mono uppercase font-bold text-sm transition-all clip-corner-br ${
                activeTab === 'sos' 
                ? 'bg-neon-green text-bunker-950' 
                : 'bg-bunker-900 text-slate-500 border border-white/10 hover:text-white'
            }`}
          >
              {t.admin.tabs.sos}
          </button>
          <button 
            onClick={() => setActiveTab('projects')}
            className={`px-6 py-3 font-mono uppercase font-bold text-sm transition-all clip-corner-br ${
                activeTab === 'projects' 
                ? 'bg-neon-green text-bunker-950' 
                : 'bg-bunker-900 text-slate-500 border border-white/10 hover:text-white'
            }`}
          >
              {/* @ts-ignore */}
              {t.admin.tabs.projects}
          </button>
      </div>

      {/* Stats (Dynamic based on Tab) */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
         {activeTab === 'users' ? (
             <>
                <div className="bg-bunker-900 border border-white/10 p-6 flex items-center justify-between group hover:border-neon-green/50 transition-colors">
                    <div>
                        <div className="text-slate-400 text-xs font-mono uppercase mb-2">{t.admin.stats.users}</div>
                        <div className="text-3xl font-tech text-white">{users.length}</div>
                    </div>
                    <Users className="text-neon-green opacity-50 group-hover:opacity-100 transition-opacity" size={40} />
                </div>
                {/* ... other user stats ... */}
             </>
         ) : activeTab === 'sos' ? (
             <>
                <div className="bg-bunker-900 border border-white/10 p-6 flex items-center justify-between group hover:border-neon-green/50 transition-colors">
                    <div>
                        <div className="text-slate-400 text-xs font-mono uppercase mb-2">Total Tickets</div>
                        <div className="text-3xl font-tech text-white">{tickets.length}</div>
                    </div>
                    <Siren className="text-neon-green opacity-50 group-hover:opacity-100 transition-opacity" size={40} />
                </div>
             </>
         ) : (
             <>
                 <div className="bg-bunker-900 border border-white/10 p-6 flex items-center justify-between group hover:border-neon-green/50 transition-colors">
                    <div>
                        <div className="text-slate-400 text-xs font-mono uppercase mb-2">Total Projects</div>
                        <div className="text-3xl font-tech text-white">{projects.length}</div>
                    </div>
                    <FileText className="text-neon-green opacity-50 group-hover:opacity-100 transition-opacity" size={40} />
                </div>
                <div className="bg-bunker-900 border border-white/10 p-6 flex items-center justify-between group hover:border-neon-cyan/50 transition-colors">
                    <div>
                        <div className="text-slate-400 text-xs font-mono uppercase mb-2">Pending</div>
                        <div className="text-3xl font-tech text-white">{projects.filter(p => p.status === 'pending').length}</div>
                    </div>
                    <AlertTriangle className="text-neon-cyan opacity-50 group-hover:opacity-100 transition-opacity" size={40} />
                </div>
             </>
         )}
      </div>

      {/* Content Area */}
      <div className="bg-bunker-900 border border-white/10 clip-corner relative min-h-[400px]">
         <div className="p-6 border-b border-white/10 flex justify-between items-center">
            <h2 className="text-xl font-bold text-white flex items-center gap-2">
                {activeTab === 'users' ? <Users size={20} className="text-slate-400"/> : activeTab === 'sos' ? <Siren size={20} className="text-slate-400"/> : <FileText size={20} className="text-slate-400"/>}
                {activeTab === 'users' ? t.admin.users : activeTab === 'sos' ? t.admin.tabs.sos : t.admin.tabs.projects}
            </h2>
            <div className="flex items-center gap-4">
                <div className="text-xs font-mono text-slate-500 hidden md:block">DB_CONNECTION: {loading ? 'FETCHING...' : 'ESTABLISHED'}</div>
                {activeTab === 'users' && (
                    <button 
                        onClick={() => handleOpenUserModal()} 
                        className="flex items-center gap-2 bg-neon-green/10 text-neon-green border border-neon-green/30 px-4 py-2 text-xs font-mono font-bold uppercase hover:bg-neon-green hover:text-bunker-950 transition-all"
                    >
                        <Plus size={14} />
                        {t.admin.actions.addUser}
                    </button>
                )}
            </div>
         </div>

         <div className="overflow-x-auto">
            {loading ? (
                 <div className="p-12 flex justify-center text-neon-green animate-pulse"><Loader /></div>
            ) : (
                <>
                {/* USERS TABLE */}
                {activeTab === 'users' && (
                    <table className="w-full text-left">
                        <thead className="bg-bunker-950 text-slate-500 font-mono text-xs uppercase">
                            <tr>
                                <th className="p-4">{t.admin.table.email}</th>
                                <th className="p-4">{t.admin.table.role}</th>
                                <th className="p-4">Business</th>
                                <th className="p-4">Subs</th>
                                <th className="p-4 text-right">{t.admin.table.actions}</th>
                            </tr>
                        </thead>
                        <tbody className="text-sm font-mono">
                            {users.map((user) => (
                                <tr key={user.id} className="border-b border-white/5 hover:bg-white/5 transition-colors">
                                    <td className="p-4 text-white font-bold">{user.email}</td>
                                    <td className="p-4">
                                        <span className={`px-2 py-0.5 text-[10px] border rounded ${
                                            user.role === 'ADMIN' ? 'text-neon-red border-neon-red/30 bg-neon-red/10' : 'text-neon-cyan border-neon-cyan/30 bg-neon-cyan/10'
                                        }`}>
                                            {user.role}
                                        </span>
                                    </td>
                                    <td className="p-4 text-slate-400">{user.business_name}</td>
                                    <td className="p-4 text-slate-400 text-xs">
                                        {user.subscriptions?.sos_business && (
                                            <span className="text-neon-green border border-neon-green/30 px-1 rounded bg-neon-green/10">SOS</span>
                                        )}
                                    </td>
                                    <td className="p-4 flex justify-end gap-2">
                                        <button onClick={() => handleOpenUserModal(user)} className="p-2 text-slate-400 hover:text-white hover:bg-white/10 rounded">
                                            <Edit size={14} />
                                        </button>
                                        <button onClick={() => handleDeleteUser(user.id)} className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-500/10 rounded">
                                            <Trash2 size={14} />
                                        </button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                )}

                {/* SOS TABLE */}
                {activeTab === 'sos' && (
                    <table className="w-full text-left">
                        <thead className="bg-bunker-950 text-slate-500 font-mono text-xs uppercase">
                            <tr>
                                <th className="p-4">{t.admin.sos_table.id}</th>
                                <th className="p-4">{t.admin.sos_table.user}</th>
                                <th className="p-4">{t.admin.sos_table.issue}</th>
                                <th className="p-4">{t.admin.sos_table.status}</th>
                                <th className="p-4">{t.admin.sos_table.cost}</th>
                                <th className="p-4">{t.admin.sos_table.paid}</th>
                                <th className="p-4 text-right">{t.admin.sos_table.actions}</th>
                            </tr>
                        </thead>
                        <tbody className="text-sm font-mono">
                            {tickets.map((ticket) => (
                                <tr key={ticket.id} className="border-b border-white/5 hover:bg-white/5 transition-colors">
                                    <td className="p-4 text-neon-green">SOS-{ticket.id}</td>
                                    <td className="p-4 text-white">
                                        <div>{ticket.user_email}</div>
                                        <div className="text-[10px] text-slate-500">{new Date(ticket.created_at).toLocaleDateString()}</div>
                                    </td>
                                    <td className="p-4 text-slate-400 max-w-xs truncate">{ticket.issue_type}</td>
                                    <td className="p-4">
                                        <span className={`px-2 py-0.5 text-[10px] uppercase border ${
                                            ticket.status === 'resolved' ? 'text-neon-green border-neon-green/30 bg-neon-green/10' :
                                            ticket.status === 'pending' ? 'text-yellow-500 border-yellow-500/30 bg-yellow-500/10' :
                                            'text-slate-400 border-slate-500/30'
                                        }`}>
                                            {ticket.status}
                                        </span>
                                    </td>
                                    <td className="p-4 text-slate-300">
                                        <div>{ticket.cost}</div>
                                        {ticket.market_cost && ticket.market_cost !== '-' && (
                                            <div className="text-[10px] text-slate-500">Mkt: {ticket.market_cost}</div>
                                        )}
                                    </td>
                                    <td className="p-4">
                                        {ticket.is_paid ? <span className="text-neon-green">YES</span> : <span className="text-red-500">NO</span>}
                                    </td>
                                    <td className="p-4 flex justify-end gap-2">
                                        <button onClick={() => handleOpenSosModal(ticket)} className="p-2 text-slate-400 hover:text-white hover:bg-white/10 rounded">
                                            <Edit size={14} />
                                        </button>
                                        <button onClick={() => handleDeleteTicket(ticket.id)} className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-500/10 rounded">
                                            <Trash2 size={14} />
                                        </button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                )}

                {/* PROJECTS TABLE */}
                {activeTab === 'projects' && (
                    <table className="w-full text-left">
                        <thead className="bg-bunker-950 text-slate-500 font-mono text-xs uppercase">
                            <tr>
                                <th className="p-4">{/* @ts-ignore */}{t.projects.id}</th>
                                <th className="p-4">{/* @ts-ignore */}{t.admin.sos_table.user}</th>
                                <th className="p-4">{/* @ts-ignore */}{t.projects.name}</th>
                                <th className="p-4">{/* @ts-ignore */}{t.projects.status}</th>
                                <th className="p-4">{/* @ts-ignore */}{t.projects.price}</th>
                                <th className="p-4">{/* @ts-ignore */}{t.projects.eta}</th>
                                <th className="p-4 text-right">{t.admin.sos_table.actions}</th>
                            </tr>
                        </thead>
                        <tbody className="text-sm font-mono">
                            {projects.map((project) => (
                                <tr key={project.id} className="border-b border-white/5 hover:bg-white/5 transition-colors">
                                    <td className="p-4 text-neon-green">PRJ-{project.id}</td>
                                    <td className="p-4 text-white">
                                        <div>{project.user_email}</div>
