import React, { useEffect, useState } from 'react';
import { useLanguage } from '../lib/LanguageContext';
import { supabase } from '../lib/supabase';
import { Users, Database, ShieldAlert, Terminal, Trash2, Edit, Loader, Plus, X, Save, Lock, Mail, Building, ToggleLeft, ToggleRight, AlertTriangle, Siren, DollarSign, Calendar, CheckSquare, FileText, CheckCircle } from 'lucide-react';

// ... (previous interfaces) ...
interface AdminFormData {
  email: string;
  password: string;
  role: string;
  business_name: string;
  subscriptions: {
    [key: string]: any;
  };
}

interface SosTicketData {
    id: number | null;
    status: string;
    issue_type: string;
    urgency: string;
    description: string;
    solution: string;
    cost: string;
    market_cost: string;
    is_paid: boolean;
    created_at: string;
}

interface ProjectData {
    id: number | null;
    status: string;
    project_name: string;
    description: string;
    price: string;
    eta: string;
    completed_at: string;
    contact_info: string;
}

export const Admin: React.FC = () => {
  const { t } = useLanguage();

  // Data States
  const [users, setUsers] = useState<any[]>([]);
  const [tickets, setTickets] = useState<any[]>([]);
  const [projects, setProjects] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  // UI States
  const [activeTab, setActiveTab] = useState<'users' | 'sos' | 'projects'>('users');

  // Modal States
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isSosModalOpen, setIsSosModalOpen] = useState(false);
  const [isProjectModalOpen, setIsProjectModalOpen] = useState(false);

  // Message Modal
  const [messageModal, setMessageModal] = useState({ 
    isOpen: false, 
    title: '', 
    text: '', 
    isError: false 
  });

  // Editing States
  const [editingUserId, setEditingUserId] = useState<number | null>(null);
  const [editingTicketId, setEditingTicketId] = useState<number | null>(null);
  const [editingProjectId, setEditingProjectId] = useState<number | null>(null);

  // Forms
  const [userFormData, setUserFormData] = useState<AdminFormData>({
    email: '',
    password: '',
    role: 'CLIENT',
    business_name: '',
    subscriptions: { sos_business: false }
  });

  const [sosFormData, setSosFormData] = useState<SosTicketData>({
      id: null,
      status: 'pending',
      issue_type: '',
      urgency: '',
      description: '',
      solution: '',
      cost: '-',
      market_cost: '-',
      is_paid: false,
      created_at: ''
  });

  const [projectFormData, setProjectFormData] = useState<ProjectData>({
      id: null,
      status: 'pending',
      project_name: '',
      description: '',
      price: '-',
      eta: '',
      completed_at: '',
      contact_info: ''
  });

  const fetchUsers = async () => {
    const { data, error } = await supabase.from('app_users').select('*').order('id', { ascending: true });
    if (error) console.error("Error fetching users:", error);
    if (data) setUsers(data);
  };

  const fetchTickets = async () => {
    const { data, error } = await supabase
        .from('sos_tickets')
        .select('*')
        .order('created_at', { ascending: false });
    if (error) console.error("Error fetching tickets:", error);
    if (data) setTickets(data);
  };

  const fetchProjects = async () => {
      const { data, error } = await supabase
        .from('service_orders')
        .select('*')
        .order('created_at', { ascending: false });
      if (error) console.error("Error fetching projects:", error);
      if (data) setProjects(data);
  };

  const fetchData = async () => {
    setLoading(true);
    await Promise.all([fetchUsers(), fetchTickets(), fetchProjects()]);
    setLoading(false);
  };

  useEffect(() => {
    fetchData();
  }, []);

  // --- Message Helper ---
  const showMessage = (title: string, text: string, isError = true) => {
    setMessageModal({ isOpen: true, title, text, isError });
  };
  const closeMessage = () => setMessageModal(prev => ({ ...prev, isOpen: false }));


  // --- USER Logic (Keep existing) ---
  const handleOpenUserModal = (user?: any) => {
    if (user) {
        setEditingUserId(user.id);
        let userSubs = user.subscriptions;
        if (typeof userSubs === 'string') {
            try { userSubs = JSON.parse(userSubs); } catch(e) { console.error("Error parsing subs", e); }
        }
        if (!userSubs) userSubs = { sos_business: false };

        setUserFormData({
            email: user.email,
